module RefModule(output reg sig_out, input clock, reset, sig_in);reg [3:0] obf_Q;
    wire J, K;

    assign J = &obf_Q[3:1],
           K = ~(|obf_Q[3:1]);

    always @(posedge clock) begin
        if(~reset)
            obf_Q <= 4'b0;
        else begin
            obf_Q[3:1] <= obf_Q[2:0];
            obf_Q[0] <= sig_in; 
        end
    end

    always @(posedge clock) begin
        if(~reset)
            sig_out <= 1'b0;
        else begin
            case({J, K})
                2'b01: sig_out <= 1'b0;
                2'b10: sig_out <= 1'b1;
                2'b11: sig_out <= ~sig_out;
                default: ; 
            endcase
        end
    end

endmodule
